var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으음…","JPN":"うーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크리스 양? 정신이 드나?","JPN":"クリス君？　気がついたのかね？","ENG":"Chris? Are you okay?","TWN":"克莉絲？你醒了？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사장님…?","JPN":"社長……？","ENG":"Boss...?","TWN":"老闆……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"방금 저 이상한 꿈을 꿨어요.","JPN":"私、今変な夢を見たんです。","ENG":"I just had the weirdest dream.","TWN":"我剛剛做了一個奇怪的夢。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사장님이 어둠 속에서 사람 머릴 가지고 나왔는데, 그게 갑자기 눈을 뜨더니 막 웃으면서…","JPN":"社長が闇の中から人の頭を持ってきたんですけど、それがいきなり目を開いて笑いながら……","ENG":"You came out of the dark, holding a person's head, and it suddenly opened its eyes and smiled–","TWN":"老闆從黑暗中拿出一個人頭，那個人頭突然睜開眼睛，還對我笑了起來……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SAW_REAPER_HEAD_ONLY","text":{"KOREA":"으아앙! 여기서 꺼내줘요오!","JPN":"わあーん！　ここから出してぇ！","ENG":"Aaagh! Let me out of here!","TWN":"嗚啊啊！快放我出去！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_METAL_KNOCK"},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"와, 아직도 꿈이구나.","JPN":"うわ、まだ夢の中なんだ。","ENG":"Whoa, I guess I'm still dreaming.","TWN":"哇，原來我還在做夢啊。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"예니카 시로코바.","JPN":"イェニカ・シロコバ。","ENG":"Yanikka Shirokova.","TWN":"耶妮卡·西羅科娃。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"챔버의 관리국 공인인 당신이 왜 이런 곳에 있는 겁니까?","JPN":"チェンバーの管理局公認であるあなたが、どうしてここにいるんですか？","ENG":"What's the Chamber's official doing in a place like this?","TWN":"作為管理局認證制裁者的你，為什麼會在這種地方？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_HEAD_ONLY","text":{"KOREA":"그럴 수도 있지 않나요? 관리국의 고된 업무를 수행하다 보면 조난 당할 수도 있는 거고요!","JPN":"こんなこともありませんか？　管理局のきつい業務を遂行していると、遭難することだってあるんですし！","ENG":"Can't I be here? I could have ended up stranded here doing the Administration's arduous work!","TWN":"很、很合理吧？管理局的任務這麼繁重，也可能會遇到意外的！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"S급 카운터가 이면세계에서 조난이라니 설득력이 없군요.","JPN":"S級カウンターが裏世界で遭難するなんて、説得力がないですよ。","ENG":"It's unconvincing that an S Grade Counter got stranded in the Counterside.","TWN":"S級制裁者在異界遇險，真是難以置信。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"게다가 당신은 지금 아케론의 감옥을 지키고 있어야 할 텐데요?","JPN":"それに、あなたは今アケロンの牢獄を守っているはずですが。","ENG":"Also, shouldn't you be guarding Acheron right now?","TWN":"而且你現在應該在守衛黃泉監獄吧？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"윽… 그건…","JPN":"うっ……それは……","ENG":"Ngh... That's...","TWN":"呃…… 那個……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"에잇!","JPN":"えいっ！","ENG":"Errgh!","TWN":"哎呀！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_07"},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"앗, 자기 혀를 깨물었어?","JPN":"あっ、自分の舌を噛んだ？","ENG":"Huh? Did she just bite her own tongue?","TWN":"啊，咬到自己的舌頭了？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"깨꼬닥-","JPN":"ガクッー","ENG":"Bleh.","TWN":"暈……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"죽은 척은 통하지 않습니다.","JPN":"死んだふりは通用しません。","ENG":"Playing dead won't work on me.","TWN":"裝死是行不通的。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"머리만 남은 채로도 살아있는 마당에 그런 자해로 죽을 리 없잖습니까.","JPN":"頭だけ残っても生きているくせに、そんな自害で死ぬわけがないでしょう。","ENG":"There's no way you'll die from that when you're alive and well with only your head.","TWN":"只剩下頭都能活著，怎麼可能會因為自殘而死呢。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…칫.","JPN":"……ちっ。","ENG":"...Tch.","TWN":"……嘖。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아무튼 전 아무것도 말하지 않을 거예요! 아무리 절 고문하고 괴롭혀도 소용없을 걸요?","JPN":"とにかく、私は何も話しませんから！　いくら私を拷問していじめても無駄ですからね？","ENG":"Anyway, I'm not saying anything! No amount of torture will make me spill, you got that?","TWN":"反正我什麼都不會說的！無論你怎麼拷問或折磨我都沒用的！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여기까지 오게 된 경위를 억지로 말하게 할 생각은 없네.","JPN":"ここまで来た経緯を無理やり言わせるつもりはない。","ENG":"We have no intention of forcing you to tell us how you ended up here.","TWN":"我們不打算強迫你說出你來這裡的原因。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 자네가 침묵하면, 자네의 담당자인 잭슨에게 그 책임을 물을 수 밖에 없어.","JPN":"だが君が話してくれないと、君の担当であるジャクソンにその責任を問うしかないんだ。","ENG":"But if you remain silent, I will have no choice but to hold your boss Jackson responsible.","TWN":"但是如果你保持沉默，我只能把責任算到你的負責人傑森頭上了。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그건 안돼요!","JPN":"それはダメです！","ENG":"Don't do that!","TWN":"不行！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"저 혼자 독단적으로 움직인 것 뿐이거든요? 시니어님이 명령한 게 절대 아니라고요!","JPN":"私1人の独断で動いただけなんです。決してシニアが命令したわけじゃありません！","ENG":"I was acting on my own, okay? This has nothing to do with the Senior's orders!","TWN":"我只是獨自行動，絕對不是Senior命令的！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"잭슨과 확실히 관련이 있나보군요.","JPN":"確かにジャクソンと関係があるようですね。","ENG":"It seems that Jackson definitely has something to do with it.","TWN":"看來確實和傑森有關。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SUSPRIRSE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 거짓말을 못하는 타입이군.","JPN":"そうだな。噓がつけないタイプのようだ。","ENG":"Yeah. She's a bad liar.","TWN":"好吧，看來她是不會說謊的類型。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"으윽… 피를 너무 오래 못 마셔서 판단력이 너무 흐려졌…","JPN":"ううっ……長い間血を飲んでなくて判断力が鈍った……","ENG":"Ngh... My judgment is blurred because I haven't been able to drink any blood for so long...","TWN":"呃……太久沒喝血了，判斷力變得弱了……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"앗!","JPN":"あっ！","ENG":"Ah!","TWN":"啊！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"피를 못 마셨다고?","JPN":"血を飲んでいないですって？","ENG":"Did you say you drink any blood?","TWN":"沒喝到血？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러고 보니, 예니카 양은 내 손을 물려고 했었지.","JPN":"そういえば、イェニカ君は私の手を噛もうとしていたな。","ENG":"Come to think of it, Yanikka did try to bite my hand.","TWN":"這麼說來，耶妮卡曾試圖咬我的手指。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정체가 궁금해지는군.","JPN":"正体が気になる。","ENG":"What are you?","TWN":"我很好奇你的真實身份。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"저… 이제 말 안 할래요.","JPN":"私……もう喋りません。","ENG":"Uh... I'm going to stop talking now.","TWN":"我……現在和你們沒什麼好說的了。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"창백한 달 현상의 관측 이후, 북방합의체는 그것과 관련된 키메라 실험을 진행한 적이 있죠.","JPN":"青白い月現象が観測された後、北方合意体がそれと関係があるキメラの実験を行ったことがありました。","ENG":"After the observation of the Pale Moon phenomenon, the Northern Union conducted chimera experiments related to it.","TWN":"在觀測到蒼月現象後，北方和議會曾進行過與之相關的混合體實驗。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그중 성공적이라 할 수 있었던 피험자는 몸을 관통 당하고 사지 일부가 절단되어도 다시 회복했습니다.","JPN":"その中で成功したと言えるような被験者は体を貫通されても、四肢の一部が切断されても再び回復したのです。","ENG":"Among them, a successful case subject could regenerate portions of its body even after being pierced or amputated.","TWN":"其中，有一個被視為成功的實驗對象即使遭受身體上的貫穿，或者四肢部分的切斷也能再次恢復如初。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그리고 피험자가 겪는 가장 특징적인 부작용은 타인의 피를 갈구한다는 것.","JPN":"そして被験者が経験するもっとも特徴的な副作用は、他人の血を渇望するようになること。","ENG":"Also, the most peculiar side effect the test subject experienced was a craving for human blood.","TWN":"並且，受試者所表現出的最為顯著的副作用，便是對人血有極度的渴望。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국 데이터에는 예니카 양의 카운터 능력이 강한 재생력이라고 기술되어 있었네.","JPN":"管理局のデータにはイェニカ君のカウンター能力が強い再生力だと記述されていた。","ENG":"In the Administration's database, Yanikka's Counter ability is written as a powerful regenerative ability.","TWN":"管理局資料中記載著，耶妮卡的制裁者能力是強大的再生力。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그게 사실이라면, 몸을 재생하지 못하는 지금은 CRF가 고갈되었단 뜻일 테고, 진작에 그림자로 변했어야 해.","JPN":"だがそれが事実なら、体を再生できない今はCRFが枯渇しているという意味であり、すでにシャドウになっていないとおかしい。","ENG":"But if that is true, it would mean that her CRF has been depleted as her body isn't regenerating, and she should have already turned into a Shadow by now.","TWN":"但如果那是真的，無法再生身體就就表示CRF早已枯竭，現在早就應該變成暗影了。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그 말씀은, 지금 예니카 씨에게 부족한 게 CRF가 아니라는 건가요?","JPN":"ってことは、イェニカさんに足りないものはCRFじゃないってことですか？","ENG":"Are you saying that what Yanikka lacks right now isn't CRF?","TWN":"你的意思是，現在耶妮卡缺少的不是CRF嗎……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうだな。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그 강한 재생력의 원동력이 피라면, 앞뒤가 맞아 떨어지지.","JPN":"だが、その強い再生力の原動力が血液ならつじつまが合う。","ENG":"But if her powerful regenerative ability stems from blood, it makes perfect sense.","TWN":"但是如果那強大的再生力源自於血液的話，那就說得通了。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"목 말라… 못 참겠어요!","JPN":"喉渇いた……もう我慢できません！","ENG":"I'm thirsty... I can't stand it!","TWN":"我……好渴……快忍不了！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"빌어먹을! 상황실! 가스 살포해!","JPN":"くそっ！　緊急対応室！　ガスを散布しろ！","ENG":"Dammit! Situation room! Release the gas!","TWN":"該死！情況室！釋放毒氣！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"경비를 데려와! 저걸 제압하라고!","JPN":"警備を連れて来い！　あれを取り押さえるんだ！","ENG":"Bring the guards! Apprehend her!","TWN":"叫警衛來！快制服她！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L13_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"으아아아악!!!","JPN":"うああああ！！！","ENG":"AAAAARGH!!!","TWN":"啊啊啊啊啊！！！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아…?","JPN":"あっ……？","ENG":"Huh...?","TWN":"啊……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"설마, 저희가 실험 영상에서 본 그 분홍머리 아이가… 예니카 씨?","JPN":"まさか、私たちが実験の映像で見たあのピンクの髪の子どもって……イェニカさん？","ENG":"Wait, the pink-haired girl we saw in the test footage... was that Yanikka?","TWN":"難道，我們在實驗影片中看到的那個粉紅頭髮的孩子是…… 耶妮卡？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"실험이요?","JPN":"実験ですか？","ENG":"Test...?","TWN":"實驗？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"당신들이 그걸 어떻게 아는 거죠?","JPN":"あなたたちがどうしてそれを知っているんですか？","ENG":"How do you know about that?","TWN":"你們是怎麼知道這些的？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"질문은 이쪽에서 합니다.","JPN":"質問はこちらがします。","ENG":"We'll ask the questions.","TWN":"現在是我們在問問題。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"말씀해보시죠.","JPN":"話してみてください。","ENG":"So tell us.","TWN":"請說吧。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"잭슨이 북방합의체와 공모해, 당신을 실험으로 개조하고 장기 말처럼 이용한 겁니까?","JPN":"ジャクソンが北方合意体と共謀して、あなたを実験で改造し手駒のように利用したんですか？","ENG":"Did Jackson conspire with the Northern Union to alter you through an experiment and use you as their pawn?","TWN":"傑森與北方和議會勾結，把你改造成實驗品，像棋子一樣利用你嗎！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그건…","JPN":"それは……","ENG":"I...","TWN":"那個……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그렇지 않아!!","JPN":"そうじゃない！！","ENG":"That's not true!!","TWN":"不是這樣的！！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"윽…?! 갑자기 오한이…","JPN":"うっ……！？　急に寒気が……","ENG":"Ngh...?! I suddenly got chills...","TWN":"呃……？！突然感到一陣寒意……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"날 이렇게 만든 나쁜 놈들은 따로 있어…!","JPN":"私をこんな風にした悪いやつらは他にいるの……！","ENG":"The bastards who made me like this are different...!","TWN":"把我變成這樣的壞人是別人……！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"잭슨 씨는 오히려 내 은인이라고요!","JPN":"ジャクソンさんは、むしろ私の恩人なんです！","ENG":"Mr. Jackson is the one who saved me!","TWN":"傑森反而是我的恩人！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잘잘못을 따지는 건 나중이라도 늦지 않네.","JPN":"是非を問うのは後からでも遅くない。","ENG":"We can quibble over whose fault it is later.","TWN":"關於其中的對錯以後再追究也不遲。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금은 실종된 잭슨을 찾는 게 우선이니 말이야.","JPN":"今は失踪したジャクソンを探すのが優先だからな。","ENG":"Right now, our priority is finding Jackson.","TWN":"現在最重要的是找到失蹤的傑森。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"실종이요? 잭슨 씨가요?","JPN":"失踪？　ジャクソンさんがですか？","ENG":"Finding Mr. Jackson? He's gone missing?","TWN":"失蹤了？傑森嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"챔버를 떠나 북방합의체 영토로 진입한 뒤 행적이 끊겼습니다.","JPN":"チェンバーを出て北方合意体の領土に進入した後、行方不明になりました。","ENG":"After he left Chamber and entered the Northern Union territory, his whereabouts are unknown.","TWN":"他在離開強巴進入北方和議會領土後便行蹤不明。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저희가 그 소식을 접했을 땐, 이미 일주일이 지난 뒤였죠.","JPN":"私たちがそのことを知った時には、すでに1週間も過ぎていました。","ENG":"By the time we got word, a week had already passed.","TWN":"我們聽到這個消息的時候，已經是一週以後了。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그럴 수가… 안돼.","JPN":"そんな……ダメ。","ENG":"That can't be... No...","TWN":"怎麼會……不……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잭슨을 찾으려면, 우리에겐 단서가 필요하네.","JPN":"ジャクソンを探すために、私たちには手がかりが必要だ。","ENG":"In order to find him, we need clues.","TWN":"要找到傑森，我們需要一些線索。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"뭔가 도움이 될만한 정보라도 있나?","JPN":"何か役に立ちそうな情報はないかね？","ENG":"Do you have any information that can help us?","TWN":"你有什麼有用的情報嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"정보…….","JPN":"情報……","ENG":"Information...","TWN":"情報……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"잭슨 씨는 북방합의체의 기밀을 얻기 위해, 그 사람들과 오랫동안 협력했어요.","JPN":"ジャクソンさんは北方合意体の機密を手に入れるために、あの人たちと長い間協力してきたんです。","ENG":"Mr. Jackson cooperated with the Northern Union for a long time to obtain their secrets.","TWN":"傑森為了獲取北方和議會的機密，和那些人合作了很長時間。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어쩌면 그것과 연관된 일로 납치 당한 걸지도 몰라요.","JPN":"もしかしたらそれと関係があることで拉致されたのかもしれません。","ENG":"Maybe he was kidnapped for something related to that.","TWN":"也許是因為那樣才被綁架了。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"북방합의체와의 협력이라.","JPN":"北方合意体との協力か。","ENG":"Cooperation with the Northern Union...","TWN":"與北方和議會合作啊。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"솔직하게 말해줘서 고맙네.","JPN":"素直に話してくれてありがとう。","ENG":"Thank you for being honest with us.","TWN":"謝謝你坦誠告知。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"은인 오라버니… 아니, 관리자님.","JPN":"恩人のお兄さん……いや、管理者さん。","ENG":"My savior... I mean, Administrator.","TWN":"救命恩人小哥哥……不，管理者。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"저도 같이 갈래요. 잭슨 씨를 찾는 걸 돕게 해주세요!","JPN":"私も一緒に行きます。ジャクソンさんを探すのを手伝わせてください！","ENG":"I want to come with. Let me help you find Mr. Jackson!","TWN":"也帶我和你們一起走，請讓我幫忙尋找傑森吧！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"당신의 규정 위반에 대한 처분은 차치하더라도-","JPN":"あなたの規定違反に関する処分は置いておくとしても……","ENG":"Aside from the punishment for violating the rules...","TWN":"暫且不論你違反規定的處罰。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"솔직히 머리만 남은 당신은 별로 도움이 되지 않을 것 같습니다만.","JPN":"正直頭だけのあなたはあまり役に立ちそうにないんですが。","ENG":"I don't think you'll be of much help if you're just a head, honestly.","TWN":"說實話，只剩下腦袋的你好像沒什麼用處啊。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"분명 도움 될 걸요?","JPN":"きっと役に立ちますよ？","ENG":"I beg to differ.","TWN":"肯定會有幫助的好嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"저 잭슨 씨의 피를 먹은 적이 있어서 잭슨 씨가 어디 있는지 감으로 찾을 수 있거든요.","JPN":"私、ジャクソンさんの血を飲んだことがあるからジャクソンさんがどこにいるのか勘で探せるんです。","ENG":"I've tasted Mr. Jackson's blood before. So, I can use my senses to find out where he is.","TWN":"我曾經喝過傑森的血，所以我能憑感覺找到他在哪裡。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"피를 먹었다고요?","JPN":"血を飲んだんですか？","ENG":"You drank his blood?","TWN":"喝過……血？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"당신이 시니어의 피를 먹게 된 그 경위도 의문이긴 합니다만…","JPN":"あなたがシニアの血を飲むようになったその経緯も疑問ではありますが……","ENG":"I would ask how you came to drink his blood, but...","TWN":"雖然我很疑惑你喝血的動機……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"우선, 그 피를 마셨다는 사실이 저희에게 무슨 도움이 되는지 묻고 싶군요.","JPN":"まず、その血を飲んだという事実が私たちにとって何の役に立つのかが聞きたいですね。","ENG":"Firstly, I want to ask how that fact will benefit us.","TWN":"但是首先，我想問一下，這對我們有什麼幫助？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"전 피를 마신 사람이 어디에 있는지 알 수 있어요. 일종의 유대감이랄까?","JPN":"私は血を飲んだ人がどこにいるのかわかるんです。一種の連帯感というか。","ENG":"After I drink someone's blood, I can tell where they are. It's like a sort of bond, I think?","TWN":"只要喝了血，我就能知道那個人在哪裡。這算是一種聯絡吧？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"게다가 저 어둠 속에서 나온 뒤로, 그 유대감이 멀지 않은 곳에서 느껴지기 시작했거든요.","JPN":"それに私、闇から出た後からその連帯感を遠くないところから感じ始めたんです。","ENG":"And after coming out of that dark pit, I'm getting the feeling that the bond is nearby.","TWN":"而且從那個坑裡出來後，我感覺到那種羈絆就在不遠處的某個地方！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그건 잭슨이 근처에 있다는 뜻입니까?","JPN":"それはジャクソンがこの辺りにいるという意味ですか？","ENG":"Does that mean Jackson is close by?","TWN":"那是說，傑森他就在附近嗎?"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아마도… 요?","JPN":"たぶん……？","ENG":"Maybe...?","TWN":"或許……吧？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"적어도 연관은 있을 거라 확신해요!","JPN":"少なくとも、関係はあると確信してます！","ENG":"I'm sure it's at least related to the case!","TWN":"我確定至少會有一些關聯！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그렇다고 하는군요.","JPN":"そういうことらしいです。","ENG":"So she says.","TWN":"她是這麼說的。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"어떻게 하시겠습니까, 관리자님?","JPN":"どうなさいますか、最高管理者様？","ENG":"What do you like to do, Administrator?","TWN":"你打算怎麼做，管理者？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 유대감이란 게 뭔진 모르겠지만, 유일한 힌트를 무시할 필요는 없겠지.","JPN":"その連帯感というのが何なのかはわからないが、唯一のヒントを無視する必要はないだろう。","ENG":"I don't know what bond she's talking about, but we can't ignore the only hint we've gotten so far.","TWN":"雖然不知道那種羈絆是什麼，但也沒必要忽視唯一的線索。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앞장서게나.","JPN":"案内してくれたまえ。","ENG":"Lead the way.","TWN":"讓她帶路吧。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};